SELECT v.*, ste.site_nm AS site_nm, cd_vm.code_label AS voc_master_cd_nm, cd_vd.code_label AS voc_detail_cd_nm FROM sy_voc v LEFT JOIN sy_site ste ON ste.site_id = v.site_id LEFT JOIN sy_code cd_vm ON cd_vm.code_grp = 'VOC_MASTER' AND cd_vm.code_value = v.voc_master_cd LEFT JOIN sy_code cd_vd ON cd_vd.code_grp = 'VOC_DETAIL' AND cd_vd.code_value = v.voc_detail_cd
ORDER BY v.voc_id ASC ORDER BY v.voc_id DESC ORDER BY v.voc_nm ASC ORDER BY v.voc_nm DESC ORDER BY v.reg_date ASC ORDER BY v.reg_date DESC ORDER BY v.reg_date DESC
LIMIT #{p.limit} OFFSET #{p.offset}

