UPDATE sy_voc
site_id = #{siteId}, voc_master_cd = #{vocMasterCd}, voc_detail_cd = #{vocDetailCd}, voc_nm = #{vocNm}, voc_content = #{vocContent}, use_yn = #{useYn}, upd_by = #{updBy}, upd_date = #{updDate},
WHERE voc_id = #{vocId}
